import React, { useState, useEffect } from 'react';
import { Globe, ArrowRight } from 'lucide-react';

function HeroSection({ lang, setLang, t, scrollToSection }) {
  const [displayedText, setDisplayedText] = useState(t.hero.subtitle);
  const [isTypingComplete, setIsTypingComplete] = useState(true);



  const services = [
    { icon: '📱', text: 'Mobile App' },
    { icon: '🌐', text: 'Website' },
    { icon: '🛒', text: 'E-Commerce' },
    { icon: '🎨', text: 'Landing Page' },
    { icon: '🤖', text: 'Bot & AI' }
  ];

  const marqueeItemsVi = ['Web Thương Mại Điện Tử', 'Web Bán Hàng', 'Landing Page', 'Mobile App', 'Mạng Xã Hội', 'Bot Telegram', 'AI'];
  const marqueeItemsEn = ['E-Commerce Website', 'Business Website', 'Landing Page', 'Mobile App', 'Social Network', 'Telegram Bot', 'AI'];
  const marqueeItems = lang === 'vi' ? marqueeItemsVi : marqueeItemsEn;

  return (
    <section className="pt-44 pb-4 px-4 sm:px-6 lg:px-8 relative  flex flex-col items-center justify-center">
      <div className="max-w-7xl mx-auto text-center relative z-10">
        <h1 className="text-5xl sm:text-6xl md:text-7xl font-black text-gray-900 mb-6 leading-tight hero-title">
          {t.hero.title}
          <br />
          <span className="gradient-text inline-block mt-2 font-black relative min-h-[80px]">
            {t.hero.subtitle}

          </span>
        </h1>

        <div className="mb-8 max-w-4xl mx-auto">
          <p className="text-lg sm:text-xl md:text-2xl text-gray-600 font-medium leading-relaxed px-6 py-4 rounded-2xl inline-block bg-white/80 backdrop-blur-sm border border-gray-100 shadow-lg">
            {t.hero.description}
          </p>
        </div>

        <div className="mb-10 w-full max-w-4xl mx-auto">
          <div className="relative bg-gradient-to-r from-gray-900 via-gray-800 to-gray-900 rounded-2xl py-5 overflow-hidden shadow-2xl">
            <div className="absolute left-0 top-0 bottom-0 w-20 bg-gradient-to-r from-gray-900 to-transparent z-10"></div>
            <div className="absolute right-0 top-0 bottom-0 w-20 bg-gradient-to-l from-gray-900 to-transparent z-10"></div>

            <div className="marquee-container">
              <div className="marquee-track">
                {[...marqueeItems, ...marqueeItems].map((item, index) => (
                  <div key={index} className="marquee-item">
                    <span className="text-white font-bold text-lg tracking-wide">{item}</span>
                    <span className="text-emerald-400 text-2xl mx-6">•</span>
                  </div>
                ))}
              </div>
              <div className="marquee-track" aria-hidden="true">
                {[...marqueeItems, ...marqueeItems].map((item, index) => (
                  <div key={index} className="marquee-item">
                    <span className="text-white font-bold text-lg tracking-wide">{item}</span>
                    <span className="text-emerald-400 text-2xl mx-6">•</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>

        <div className="flex flex-wrap justify-center gap-3 mb-10 max-w-5xl mx-auto">
          {services.map((service, index) => (
            <div key={index} className="service-badge bg-white border border-gray-200 rounded-full px-5 py-2.5 flex items-center space-x-2.5 hover:scale-110 hover:border-emerald-300 hover:shadow-lg transition-all duration-300 shadow-md">
              <span className="text-xl">{service.icon}</span>
              <span className="text-gray-700 text-sm font-semibold whitespace-nowrap">{service.text}</span>
            </div>
          ))}
        </div>

        <div className="flex flex-col sm:flex-row gap-5 justify-center mb-10">
          <button onClick={() => window.location.href = '/contact'} className="group relative bg-gradient-to-r from-emerald-500 to-cyan-500 text-white px-12 py-5 rounded-2xl font-bold text-lg hover:from-emerald-600 hover:to-cyan-600 transition-all flex items-center justify-center space-x-3 hover:scale-105 shadow-xl hover:shadow-2xl">
            <span className="relative z-10 text-xl">{t.hero.btnCTA}</span>
            <ArrowRight className="w-6 h-6 relative z-10 group-hover:translate-x-2 transition-transform duration-300" />
          </button>

          <button onClick={() => scrollToSection('portfolio')} className="bg-white border-2 border-gray-200 text-gray-700 px-12 py-5 rounded-2xl font-bold text-lg hover:border-emerald-400 hover:text-emerald-600 transition-all hover:scale-105 shadow-lg hover:shadow-xl">
            <span className="text-xl">{t.hero.btnPortfolio}</span>
          </button>
        </div>

        <button onClick={() => setLang(lang === 'vi' ? 'en' : 'vi')} className="inline-flex items-center space-x-3 bg-white border border-gray-200 text-gray-600 px-7 py-3.5 rounded-xl hover:border-emerald-300 hover:text-emerald-600 transition-all hover:scale-105 shadow-md font-semibold">
          <Globe className="w-6 h-6" />
          <span>{t.hero.btnSwitch}</span>
        </button>
      </div>
    </section>
  );
}

export default HeroSection;
